module TopModule #(parameter WIDTH = 8, parameter DEPTH = 16) (
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull, rempty,
    output [WIDTH-1:0] rdata
);
    // BEGIN: Definitions
    // Dual-port RAM instance
    wire wenc, renc;
    wire [DEPTH-1:0] waddr, raddr;
    wire [WIDTH-1:0] rdata;
    reg [DEPTH-1:0] waddr_bin, raddr_bin;
    reg [DEPTH-1:0] wptr_buff, rptr_buff;
    reg [DEPTH-1:0] wptr, rptr;
    reg wfull, rempty;
    // END: Definitions
    // BEGIN: Dual-port RAM
    // Instantiate a dual-port RAM module with the specified depth and width for data storage.
    // The module has a write enable input and a read enable input, both are assigned to always be 1.
    // The write address and read address are both connected to the binary address registers waddr_bin and raddr_bin, respectively.
    // The write data input is connected to the wdata input.
    // The read data output is connected to the rdata output.
    dual_port_RAM u_dual_port_RAM (
        .wclk(wclk),
        .rclk(rclk),
        .wrstn(wrstn),
        .rrstn(rrstn),
        .wenc(wenc),
        .renc(renc),
        .waddr(waddr[DEPTH-1:0]),
        .raddr(raddr[DEPTH-1:0]),
        .wdata(wdata[WIDTH-1:0]),
        .rdata(rdata[WIDTH-1:0])
    );
    // END: Dual-port RAM
    // BEGIN: Write pointer update logic
    // The write pointer update logic is triggered on the positive edge of the write clock or the negative edge of the write reset.
    // If the write reset is active (low), the write address binary register is reset to 0.
    // If the write increment signal is high, the write address binary register is incremented by 1.
    always @(posedge wclk or negedge wrstn) begin
        if (~wrstn) begin
            waddr_bin <= 0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end
    // END: Write pointer update logic
    // BEGIN: Gray code conversion of write pointer
    // The Gray code conversion of the write pointer is done by XORing the binary address with a right-shifted version of itself.
    // The result is assigned to the write pointer register.
    always @(*) begin
        wptr <= waddr_bin ^ (waddr_bin >> 1);
    end
    // END: Gray code conversion of write pointer
    // BEGIN: Buffering of write pointer
    // The write pointer buffer register is updated on the positive edge of the write clock or the negative edge of the write reset.
    // If the write reset is active (low), the write pointer buffer is reset to 0.
    // If the write reset is not active (high), the write pointer buffer is assigned the current write pointer value.
    always @(posedge wclk or negedge wrstn) begin
        if (~wrstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end
    // END: Buffering of write pointer
    // BEGIN: Read pointer update logic
    // The read pointer update logic is triggered on the positive edge of the read clock or the negative edge of the read reset.
    // If the read reset is active (low), the read address binary register is reset to 0.
    // If the read increment signal is high, the read address binary register is incremented by 1.
    always @(posedge rclk or negedge rrstn) begin
        if (~rrstn) begin
            raddr_bin <= 0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end
    // END: Read pointer update logic
    // BEGIN: Gray code conversion of read pointer
    // The Gray code conversion of the read pointer is done by XORing the binary address with a right-shifted version of itself.
    // The result is assigned to the read pointer register.
    always @(*) begin
        rptr <= raddr_bin ^ (raddr_bin >> 1);
    end
    // END: Gray code conversion of read pointer
    // BEGIN: Buffering of read pointer
    // The read pointer buffer register is updated on the positive edge of the read clock or the negative edge of the read reset.
    // If the read reset is active (low), the read pointer buffer is reset to 0.
    // If the read reset is not active (high), the read pointer buffer is assigned the current read pointer value.
    always @(posedge rclk or negedge rrstn) begin
        if (~rrstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end
    // END: Buffering of read pointer
    // BEGIN: Full signal generation logic
    // The full signal is generated based on the comparison of the write pointer and the synchronized read pointer.
    // If the write pointer is equal to the bitwise negation of the most significant bit of the read pointer concatenated with the remaining bits of the read pointer, the write full signal is set to 1.
    // Otherwise, the write full signal is set to 0.
    always @(*) begin
        if (wptr == ~rptr_syn[DEPTH-1:0] && wptr_buff == rptr_syn[DEPTH-1:0]) begin
            wfull <= 1;
        end else begin
            wfull <= 0;
        end
    end
    // END: Full signal generation logic
    // BEGIN: Empty signal generation logic
    // The empty signal is generated based on the comparison of the read pointer and the synchronized write pointer.
    // If the read pointer is equal to the write pointer synchronized to the read clock, the read empty signal is set to 1.
    // Otherwise, the read empty signal is set to 0.
    always @(*) begin
        if (rptr == wptr_syn[DEPTH-1:0] && rptr_buff == wptr_syn[DEPTH-1:0]) begin
            rempty <= 1;
        end else begin
            rempty <= 0;
        end
    end
    // END: Empty signal generation logic
    // BEGIN: Input and output signal connections
    // The write enable input is connected to the write enable output.
    // The read enable input is connected to the read enable output.
    // The write address input is connected to the write address binary register.
    // The read address input is connected to the read address binary register.
    // The read data output is connected to the write data input.
    assign wenc = wen;
    assign renc = ren;
    assign waddr = waddr_bin[DEPTH-1:0];
    assign raddr = raddr_bin[DEPTH-1:0];
    assign rdata = wdata;
    // END: Input and output signal connections
    // BEGIN: Combinational logic for read pointer synchronization
    // The read pointer synchronized to the write clock is updated based on the read pointer buffer.
    // If the read reset is active (low), the write full signal is set to 0.
    // Otherwise, the write full signal is set to the logical negation of the read empty signal.
    always @(*) begin
        if (~wrstn) begin
            wfull <= 0;
        end else begin
            wfull <= ~rempty;
        end
    end
    // END: Combinational logic for read pointer synchronization
    // BEGIN: Combinational logic for write pointer synchronization
    // The write pointer synchronized to the read clock is updated based on the write pointer buffer.
    // If the write reset is active (low), the read empty signal is set to 0.
    // Otherwise, the read empty signal is set to the logical negation of the write full signal.
    always @(*) begin
        if (~rrstn) begin
            rempty <= 0;
        end else begin
            rempty <= ~wfull;
        end
    end
    // END: Combinational logic for write pointer synchronization
endmodule
